function maxTasks(tasks, workers, pills, strength) {
    tasks.sort((a, b) => a - b);
    workers.sort((a, b) => a - b);
    let taskIndex = 0;
    let pillIndex = pills;
    let completedTasks = 0;

    for (const workerStrength of workers) {
        while (pillIndex > 0 && workerStrength + strength >= tasks[taskIndex]) {
            workerStrength += strength;
            --pillIndex;
        }

        if (workerStrength >= tasks[taskIndex]) {
            ++taskIndex;
            ++completedTasks;
        }

        if (taskIndex >= tasks.length) {
            break;
        }
    }

    return completedTasks;
}
```


    1. First, we sort both the tasks and the workers arrays in increasing order.
2. We initialize variables: taskIndex for iterating through the tasks array, pillIndex to keep track of the available pills, and completedTasks to count the number of tasks completed.
3. Next, we iterate through the workers array, each time checking if the current worker's strength is sufficient to complete the current task by comparing it with the task's strength requirement.
4. If the worker's strength is not sufficient and we still have pills available, we increment the worker's strength by "strength" (the strength added by one pill) and decrement the number of available pills.
5. If the worker's strength is now sufficient to complete the task, we increment the task index and the completed tasks counter.
6. We stop the loop if all tasks have been completed.
7. Finally, we return the completedTasks counter.

